## 2. 최적화된 코드 (After)

### 2-1. QueryDSL Projection으로 N+1 완전 제거

**파일: `domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryCustom.kt`**

```kotlin
// AFTER: Custom Repository 인터페이스 정의
interface FollowRepositoryCustom {
    fun findFollowingListWithProfile(
        followerId: String,
        status: Int,
        cursor: String?,
        limit: Int,
    ): List<FollowProjection>

    fun countFollowing(followerId: String, status: Int): Long
}

// QueryDSL Projection DTO - SELECT 컬럼을 딱 필요한 것만
data class FollowProjection(
    val followId: String,
    val followingUserId: String,
    val nickname: String,
    val profileImageUrl: String?,
    val followedAt: LocalDateTime,
)
```

**파일: `domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepositoryImpl.kt`**

```kotlin
// AFTER: 단일 JOIN 쿼리로 N+1 완전 제거
class FollowRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : FollowRepositoryCustom {

    override fun findFollowingListWithProfile(
        followerId: String,
        status: Int,
        cursor: String?,
        limit: Int,
    ): List<FollowProjection> {
        val follow = QFollowEntity.followEntity
        val user = QUserEntity.userEntity
        val profile = QProfileEntity.profileEntity

        return queryFactory
            // Projection.constructor로 필요한 컬럼만 SELECT (SELECT * 방지)
            .select(
                Projections.constructor(
                    FollowProjection::class.java,
                    follow.id,
                    user.id,
                    user.nickname,
                    profile.imageUrl,
                    follow.createdAt,
                )
            )
            .from(follow)
            // AFTER: 단일 쿼리에 JOIN 포함 -> N+1 제거
            .innerJoin(user).on(user.id.eq(follow.followingId))
            .leftJoin(profile).on(profile.userId.eq(follow.followingId))
            .where(
                follow.followerId.eq(followerId),
                follow.status.eq(status),
                // 커서 기반 페이징: createdAt 기준 no-offset
                cursor?.let { follow.createdAt.lt(LocalDateTime.parse(it)) },
            )
            .orderBy(follow.createdAt.desc())
            .limit(limit.toLong())
            .fetch()
        // 총 쿼리 수: 1개 (JOIN 포함)
        // 예상 응답 시간: ~20~50ms
    }

    override fun countFollowing(followerId: String, status: Int): Long {
        val follow = QFollowEntity.followEntity
        return queryFactory
            .select(follow.count())
            .from(follow)
            .where(
                follow.followerId.eq(followerId),
                follow.status.eq(status),
            )
            .fetchOne() ?: 0L
    }
}
```

**파일: `domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt`**

```kotlin
