```kotlin
// AFTER: Redis 캐시 + 페이징 + N+1 제거
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        private const val FOLLOW_LIST_CACHE_KEY = "follow:list:v1"
        private const val FOLLOW_COUNT_CACHE_KEY = "follow:count:v1"
        private const val CACHE_TTL_SECONDS = 300L  // 5분 TTL
        private const val DEFAULT_PAGE_SIZE = 20
    }

    // AFTER: 단일 쿼리 + 커서 페이징 + 캐시
    @Transactional(readOnly = true)
    fun getFollowingList(
        followerId: String,
        cursor: String? = null,
        limit: Int = DEFAULT_PAGE_SIZE,
    ): FollowListResponse {
        // 첫 페이지(cursor=null)만 캐시 적용 (무효화 단순화)
        if (cursor == null) {
            val cacheKey = "$FOLLOW_LIST_CACHE_KEY:$followerId"
            val cached = redisTemplate.opsForValue().get(cacheKey)
            if (cached != null) {
                @Suppress("UNCHECKED_CAST")
                return cached as FollowListResponse
            }
        }

        // 단일 JOIN 쿼리 실행 (N+1 없음)
        val items = followRepository.findFollowingListWithProfile(
            followerId = followerId,
            status = 1,
            cursor = cursor,
            limit = limit + 1, // hasNext 판별용 +1
        )

        val hasNext = items.size > limit
        val result = FollowListResponse(
            items = items.take(limit).map { it.toResponse() },
            hasNext = hasNext,
            nextCursor = if (hasNext) items[limit - 1].followedAt.toString() else null,
        )

        // 첫 페이지 캐시 저장
        if (cursor == null) {
            val cacheKey = "$FOLLOW_LIST_CACHE_KEY:$followerId"
            redisTemplate.opsForValue().set(cacheKey, result, Duration.ofSeconds(CACHE_TTL_SECONDS))
        }

        return result
    }

    // 팔로우/언팔로우 시 캐시 무효화
    @Transactional
    fun follow(followerId: String, followingId: String) {
        // ... follow 로직 ...
        invalidateFollowCache(followerId)
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        // ... unfollow 로직 ...
        invalidateFollowCache(followerId)
    }

    private fun invalidateFollowCache(followerId: String) {
        redisTemplate.delete("$FOLLOW_LIST_CACHE_KEY:$followerId")
        redisTemplate.delete("$FOLLOW_COUNT_CACHE_KEY:$followerId")
    }
}
